    // 1. No retries needed — success on first try
    #[tokio::test]
    async fn success_on_first_try() {
        let result = execute_with_retry(
            || async { Ok(Outcome::success("done")) },
            3,
            &BackoffPolicy::None,
            "node_a",
        )
        .await;

        let outcome = result.unwrap();
        assert_eq!(outcome.status, StageStatus::Success);
