        .run(&graph)
        .await
        .expect("pipeline should succeed");

    // Graph attrs are loaded into context during initialization
    assert_eq!(
        result.final_context.get("goal"),
        Some(&serde_json::json!("Build a working pipeline")),
        "goal should be in final context"
    );
}

