}

// ---------------------------------------------------------------------------
// ReasoningEffort
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ReasoningEffort {
    Low,
    Medium,
    High,
}

// ---------------------------------------------------------------------------
// StreamEvent
// ---------------------------------------------------------------------------

#[derive(Debug, Clone)]
pub enum StreamEvent {
    ContentStart,
    ContentDelta {
        text: String,
    },
    ContentEnd,
    ToolCallStart {
        id: String,
        name: String,
    },
    ToolCallDelta {
        id: String,
        json_chunk: String,
    },
    ToolCallEnd {
        id: String,
    },
