        outline: none;
    }

    &::placeholder {
        color: $overlay;
    }

    &:disabled {
        opacity: 0.5;
        cursor: not-allowed;
    }
}

.open-btn,
.select-btn {
    padding: 8px 16px;
    background: $primary;
    color: $base;
    border: none;
    border-radius: 4px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.875rem;
    transition: background 0.15s;

    &:hover:not(:disabled) {
        background: $primary-hover;
    }

    &:disabled {
        opacity: 0.5;
        cursor: not-allowed;
    }
}

.divider {
    text-align: center;
    color: $overlay;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.browser-section {
    display: flex;
    flex-direction: column;
    gap: 8px;

    h3 {
        font-size: 0.875rem;
        font-weight: 600;
        margin: 0;
        color: $text;
    }
}

.breadcrumb {
    padding: 8px;
    background: $mantle;
    border-radius: 4px;
    font-size: 0.8rem;
}

.breadcrumb-path {
    color: $subtext;
    word-break: break-all;
}

.directory-list {
    background: $mantle;
    border: 1px solid $surface0;
    border-radius: 4px;
    max-height: 300px;
    overflow-y: auto;
}

.dir-entry {
    display: flex;
    align-items: center;
    padding: 6px 12px;
    cursor: pointer;
    color: $text;
    font-size: 0.875rem;
    transition: background 0.15s;

    &:hover {
        background: $surface0;
    }
}

.dir-icon {
    margin-right: 8px;
    color: $primary;
}

.dir-name {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.loading-indicator {
    padding: 12px;
    text-align: center;
    color: $subtext;
    font-size: 0.875rem;
}

.error-message {
    padding: 8px;
    background: rgba($error, 0.1);
    border: 1px solid rgba($error, 0.3);
    border-radius: 4px;
    color: $error;
    font-size: 0.85rem;
}

